  (e2:Entity {name: 'ANTAM ENTERPRISES N.V.'}),
  (i1:Intermediary {name: 'ANTAM ENTERPRISES N.V.'}),
  (o1:Officer {name: 'ANTAM ENTERPRISES N.V.'}),
  (a1:Address),
  (o2:Officer {name: 'ANTAM ENTERPRISES N.V.'}),
  (e3:Entity),
  (a2:Address),
  (other1:Other),
  (other2:Other)
WHERE
  e1.name = 'ANTAM ENTERPRISES N.V.' OR e2.name = 'ANTAM ENTERPRISES N.V.' OR i1.name = 'ANTAM ENTERPRISES N.V.' OR o1.name = 'ANTAM ENTERPRISES N.V.' OR other1.name = 'ANTAM ENTERPRISES N.V.' OR other2.name = 'ANTAM ENTERPRISES N.V.'
  // Validating a more specific entity with sample dates for incorporation
  e1.incorporation_date = '18-MAY-1983' OR e2.incorporation_date = '18-MAY-1983'
  // Validating intermediary relationships
  EXISTS { (e1)-[:intermediary_of]->(i1) }
  // Validating officer relationships
  EXISTS { (e1)-[:officer_of]->(o1) }
  // Validating same company relationship
  EXISTS { (e1)-[:same_company_as]->(e3) }
  // Validating address relationships
  EXISTS { (e1)-[:registered_address]->(a1) }
  // Validating similar or same name relationships
  EXISTS { (i1)-[:similar]->(o1) }
  // Validating address similarity
  EXISTS { (e1)-[:connected_to]->(a2) }
  // Validating same_name_as to Other
  EXISTS { (e1)-[:same_name_as]->(other1) }
  // Validating same_name_as to another Entity
  EXISTS { (e1)-[:same_name_as]->(e3) }
RETURN
  e1,
  e2,
  i1,
  o1,
  a1,
  o2,
  e3,
  a2,
  other1,
  other2,
  DISTINCT
  [r | (e1)-[r]->(a1)] AS entity_address_links,
  [r | (e1)-[r]->(e3)] AS entity_company_links,
  [r | (i1)-[r]->(o1)] AS intermediary_officer_links,
  [r | (e1)-[r]->(other1)] AS entity_other_links,
  [r | (e1)-[r]->(a2)] AS entity_address_connections;

